import org.moqui.context.ExecutionContext
import org.moqui.genicam.GenicamClient
import org.moqui.genicam.GenicamUtil

if (!connection) throw new IllegalArgumentException("A connection instance is required for GenICam to communicate with the camera ${request.deviceId}. Device request with name ${request.requestName}, aborted.")
if (!connection.transportConfig) throw new IllegalArgumentException("Connection transportConfig must specify the absolute path to the .cti GenTL driver.")

ExecutionContext ec = context.ec
String ctiPath = connection.transportConfig
String serialNumber = GenicamUtil.resolveSerialNumber(device, connection)

ec.logger.info("Connecting to camera with ID ${request.deviceId} using CTI ${ctiPath}.")
try (GenicamClient client = new GenicamClient(ec, ctiPath, serialNumber, request.deviceId)) {
    if ("DrtRead" == request.requestTypeEnumId) {
        client.read(request, requestItemList)
    } else if ("DrtWrite" == request.requestTypeEnumId) {
        client.write(request, requestItemList)
    } else {
        throw new IllegalArgumentException("Unsupported device request type ${request.requestTypeEnumId}. Could not send the device request with name ${request.requestName}.")
    }
}

import org.moqui.context.ExecutionContext
import org.moqui.genicam.GenicamClient
import org.moqui.genicam.GenicamUtil
import jakarta.servlet.http.HttpServletResponse
import java.io.OutputStream

ExecutionContext ec = context.ec
String serialNumber = GenicamUtil.resolveSerialNumber(device, connection)

HttpServletResponse response = (HttpServletResponse) ec.web.response
response.setContentType("multipart/x-mixed-replace; boundary=frame")
response.setHeader("Cache-Control", "no-cache, private, must-revalidate")
response.setHeader("Pragma", "no-cache")
response.setHeader("Connection", "keep-alive")

OutputStream os = response.getOutputStream()

try (GenicamClient client = new GenicamClient(ec, ctiPath, serialNumber, deviceId)) {
    // stream 100 frames (~7 seconds) as a safety-net limit for testing, or until client disconnects
    int maxFrames = 100
    int frameCount = 0

    while (frameCount < maxFrames) {
        byte[] jpegBytes = client.getFrameBytes()

        if (jpegBytes) {
            try {
                os.write(("--frame\r\nContent-Type: image/jpeg\r\nContent-Length: " + jpegBytes.length + "\r\n\r\n").getBytes())
                os.write(jpegBytes)
                os.write("\r\n".getBytes())
                os.flush()
            } catch (IOException ioEx) {
                ec.logger.info("Live stream client disconnected for camera ${serialNumber}")
                break
            }
        }
        frameCount++
        Thread.sleep(66) // ~15 FPS
    }
} catch (Throwable t) {
    ec.logger.error("GenICam Live MJPEG stream error", t)
    throw t
}

import org.moqui.context.ExecutionContext
import org.moqui.genicam.GenicamClient
import org.moqui.genicam.GenicamUtil

ExecutionContext ec = context.ec
String serialNumber = GenicamUtil.resolveSerialNumber(device, connection)
String resolvedOutputDir = GenicamUtil.resolveConfiguredPath(ec, outputDir,
        "genicam.tensors.path", GenicamUtil.DEFAULT_TENSORS_PATH)
Map<String, Object> pyResults = [:]

try (GenicamClient client = new GenicamClient(ec, ctiPath, serialNumber, deviceId)) {
    pyResults = client.acquire3dFrame()
} catch (Throwable t) {
    ec.logger.error("GenICam JEP 3D frame acquisition failed", t)
    throw t
}

if (pyResults) {
    Map<String, Object> storedTensor = GenicamUtil.storeTensorPayload(ec, serialNumber, pyResults, resolvedOutputDir)
    context.tensorId = storedTensor.get("tensorId")
    context.tensorContentId = storedTensor.get("tensorContentId")
    context.contentLocation = storedTensor.get("contentLocation")
}

iterate.script:
if (content.contentLocation) {
    java.io.File file = new java.io.File(content.contentLocation)
    if (file.exists()) {
        try {
            file.delete()
            ec.logger.info("Deleted old tensor file: ${content.contentLocation}")
        } catch (Exception e) {
            ec.logger.error("Failed to delete tensor file ${content.contentLocation}: ${e.getMessage()}")
        }
    }
}

boolean beganTx = ec.transaction.begin(null)
try {
    ec.entity.find("moqui.math.TensorContent").condition("tensorContentId", content.tensorContentId).deleteAll()
    ec.entity.find("moqui.math.TensorAxis").condition("tensorId", content.tensorId).deleteAll()
    ec.entity.find("moqui.math.Tensor").condition("tensorId", content.tensorId).deleteAll()
    ec.transaction.commit(beganTx)
    deletedCount++
} catch (Throwable t) {
    ec.transaction.rollback(beganTx, "Failed to clean tensor DB records", t)
    ec.logger.error("Failed to delete DB records for tensor ${content.tensorId}: ${t.getMessage()}")
}
